#define NORMAL 0;
#define OVERHEATED 1;
#define SHUTDOWN 2;

var reactor_state = NORMAL;

Reactor() = 
    Normal();

Normal() = 
    overheat{reactor_state = OVERHEATED;} -> Overheated();

Overheated() = 
    Wait[4]; 
    (
        cooling{reactor_state = NORMAL;} -> Normal()
        []
        emergency_shutdown{reactor_state = SHUTDOWN;} -> Shutdown()
    );

Shutdown() = Stop;

SafetyMonitor() = 
    overheat -> 
    (
        (cooling -> SafetyMonitor()) 
        timeout[3] 
        (emergency_shutdown -> Stop within[5])
    );

System() = Reactor() || SafetyMonitor();

#define shutdown_done (reactor_state == SHUTDOWN);
#assert System() deadlockfree;
#assert System() reaches shutdown_done;

